-- 1. Directory Object 생성
CREATE OR REPLACE DIRECTORY dp_export_dir AS '/u01/app/oracle/dpump/export';
CREATE OR REPLACE DIRECTORY dp_import_dir AS '/u01/app/oracle/dpump/import';

-- 2. 사용자에게 READ, WRITE 권한 부여
GRANT READ, WRITE ON DIRECTORY dp_export_dir TO hr;
GRANT READ, WRITE ON DIRECTORY dp_import_dir TO hr;

-- 3. Directory Object 및 권한 확인
SELECT directory_name, directory_path
FROM dba_directories
WHERE directory_name LIKE 'DP_%'
ORDER BY directory_name;

SELECT grantee, table_name AS directory_name, privilege
FROM dba_tab_privs
WHERE table_name LIKE 'DP_%'
AND grantor = 'SYS'
ORDER BY grantee, table_name;
